import requests
import os
from dotenv import load_dotenv

load_dotenv()
 
TENANT_ID = os.getenv("PBI_TENANT_ID")
CLIENT_ID = os.getenv("PBI_CLIENT_ID")
CLIENT_SECRET = os.getenv("PBI_CLIENT_SECRET")

GROUP_ID = "838a4381-6a88-4235-a361-df7349246528"
DATASET_ID = "eec9cbea-13fe-42f1-8a32-009f59ce9bd6"
 
token_url = f"https://login.microsoftonline.com/{TENANT_ID}/oauth2/v2.0/token"
 
payload = {
    "grant_type": "client_credentials",
    "client_id": CLIENT_ID,
    "client_secret": CLIENT_SECRET,
    "scope": "https://analysis.windows.net/powerbi/api/.default"
}

token_response = requests.post(token_url, data=payload)
print("TOKENS STATUS:", token_response.status_code)
print(token_response.text)

token_response.raise_for_status()
access_token = token_response.json()
["access_token"]

url = f"https://api.powerbi.com/v1.0/myorg/groups/{GROUP_ID}/datasets/{DATASET_ID}/refreshes?$top=5"



headers = {
    "Authorization": f"Bearer {access_token}"
}
 
response = requests.get(url, headers=headers)

print("API STATUS:", response.status_code)
print(response.text)

